import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { motion } from "framer-motion";
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const Wishlist = () => {
  const { user } = useAuth();
  const { addToCart } = useCart();
  const [wishlistItems, setWishlistItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [toastMessage, setToastMessage] = useState("");

  useEffect(() => {
    const fetchWishlist = async () => {
      try {
        const token = localStorage.getItem('token');
        const response = await axios.get("http://localhost:3000/api/v1/wishlist", {
          headers: { 'Authorization': `Bearer ${token}` }
        });
        setWishlistItems(response.data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    if (user) {
      fetchWishlist();
    }
  }, [user]);

  const handleRemoveFromWishlist = async (wishlistItemId) => {
    try {
      const token = localStorage.getItem('token');
      await axios.delete(`http://localhost:3000/api/v1/wishlist/${wishlistItemId}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      setWishlistItems(prev => prev.filter(item => item._id !== wishlistItemId));
      setToastMessage("Removed from wishlist");
      setTimeout(() => setToastMessage(""), 3000);
    } catch (err) {
      setToastMessage("Error removing item");
      console.error("Error removing from wishlist:", err);
    }
  };

  const handleAddToCartFromWishlist = async (product) => {
    const result = await addToCart(product);
    if (result.success) {
      setToastMessage("Added to cart!");
      setTimeout(() => setToastMessage(""), 3000);
    } else {
      setToastMessage("Please login to add to cart");
    }
  };

  if (loading) return <div className="text-center py-20 text-zinc-400">Loading your cherished items...</div>;
  if (error) return <div className="text-center py-20 text-red-500">Error: {error}</div>;

  return (
    <div className="min-h-screen bg-zinc-950 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-7xl mx-auto">
        {/* Toast Notifications */}
        {toastMessage && (
          <div className="fixed bottom-4 right-4 bg-zinc-800 text-white px-6 py-3 rounded-lg shadow-lg animate-slideUp">
            {toastMessage}
          </div>
        )}

        <h1 className="text-4xl font-bold text-center mb-8 text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-amber-500">
          Your Curated Collection
        </h1>
        
        {wishlistItems.length === 0 ? (
          <div className="text-center py-20">
            <div className="text-zinc-400 text-lg mb-4">Your wishlist feels lonely...</div>
            <Link 
              to="/products" 
              className="inline-block bg-red-600 hover:bg-red-700 text-white px-8 py-3 rounded-full transition-all duration-300 transform hover:scale-105"
            >
              Explore Hot Wheels
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {wishlistItems.map((item, index) => (
              <motion.div 
                key={item._id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="group relative bg-zinc-900 rounded-2xl overflow-hidden shadow-2xl hover:shadow-[0_0_30px_rgba(239,68,68,0.2)] transition-all duration-300"
              >
                <div className="aspect-square overflow-hidden">
                  <img 
                    src={item.product.image} 
                    alt={item.product.name} 
                    className="w-full h-full object-cover transform transition-transform duration-500 group-hover:scale-110"
                  />
                </div>
                
                <div className="p-6">
                  <h2 className="text-xl font-bold text-white mb-2">{item.product.name}</h2>
                  <p className="text-zinc-400 text-sm mb-4 line-clamp-2">{item.product.description}</p>
                  
                  <div className="flex items-center justify-between">
                    <span className="text-2xl font-bold text-red-500">${item.product.price.toFixed(2)}</span>
                    <div className="flex space-x-2">
                      <button 
                        onClick={() => handleRemoveFromWishlist(item._id)}
                        className="w-10 h-10 bg-red-600 hover:bg-red-700 rounded-full flex items-center justify-center transition-all"
                      >
                        <i className="fas fa-trash text-white text-sm"></i>
                      </button>
                      <button 
                        onClick={() => handleAddToCartFromWishlist(item.product)}
                        className="w-10 h-10 bg-green-600 hover:bg-green-700 rounded-full flex items-center justify-center transition-all"
                      >
                        <i className="fas fa-cart-plus text-white text-sm"></i>
                      </button>
                    </div>
                  </div>
                </div>

                <div className="absolute top-4 right-4">
                  <div className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center">
                    <i className="fas fa-heart text-white"></i>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Wishlist;
